const input = $input.first().json.body || $input.first().json;

return [
  {
    json: {
      ticket_id: input.ticket_id,
      customer_id: input.customer_id || null,
      customer_tier: input.customer_tier || "standard",
      channel: input.channel || "unknown",
      message: input.message || "",
      created_at: input.created_at || new Date().toISOString()
    }
  }
];

const normalizedTicket = $('Normalize Incoming Ticket').first().json;

// Gemini node response path
const raw =
  $json.candidates?.[0]?.content?.parts?.[0]?.text ||
  $json.output ||
  $json.text ||
  $json.content ||
  $json.message?.content ||
  $json.choices?.[0]?.message?.content;

if (!raw) {
  throw new Error("AI response text not found: " + JSON.stringify($json));
}

// на случай если модель вдруг завернёт JSON в ```json
const cleaned = String(raw)
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

let classification;

try {
  classification = JSON.parse(cleaned);
} catch (error) {
  throw new Error("AI returned invalid JSON: " + raw);
}

return [
  {
    json: {
      ...normalizedTicket,
      classification
    }
  }
];

const item = $input.first().json;
const c = item.classification || {};

const allowedCategories = [
  "billing",
  "technical_issue",
  "account_access",
  "feature_request",
  "complaint",
  "how_to_question",
  "other"
];

const allowedIntents = [
  "refund_request",
  "payment_failed",
  "duplicate_charge",
  "login_problem",
  "bug_report",
  "setup_question",
  "cancel_subscription",
  "angry_complaint",
  "unknown"
];

const allowedPriorities = ["low", "medium", "high", "urgent"];
const allowedSentiments = ["positive", "neutral", "negative"];

let category = allowedCategories.includes(c.category) ? c.category : "other";
let intent = allowedIntents.includes(c.intent) ? c.intent : "unknown";
let priority = allowedPriorities.includes(c.priority) ? c.priority : "medium";
let sentiment = allowedSentiments.includes(c.sentiment) ? c.sentiment : "neutral";

const confidence = Number(c.confidence || 0);

// deterministic business rules
if (
  category === "billing" &&
  ["refund_request", "duplicate_charge", "payment_failed"].includes(intent)
) {
  sentiment = "negative";
}

if (
  item.customer_tier === "premium" &&
  category === "billing" &&
  ["refund_request", "duplicate_charge", "payment_failed"].includes(intent)
) {
  priority = ["high", "urgent"].includes(priority) ? priority : "high";
}

if (category === "account_access" || intent === "login_problem") {
  priority = ["high", "urgent"].includes(priority) ? priority : "high";
}

if (category === "complaint" || intent === "angry_complaint") {
  priority = ["high", "urgent"].includes(priority) ? priority : "high";
  sentiment = "negative";
}

const needsHuman =
  c.needs_human === true ||
  confidence < 0.75 ||
  category === "other" ||
  intent === "unknown";

return [
  {
    json: {
      ...item,
      classification: {
        category,
        intent,
        priority,
        sentiment,
        language: c.language || "unknown",
        needs_human: needsHuman,
        confidence,
        summary: c.summary || ""
      }
    }
  }
];

const item = $input.first().json;
const c = item.classification;

let queue = "General Support";
let assignee_group = "support_l1";
let routing_reason = "Default routing";

if (c.needs_human && c.confidence < 0.75) {
  queue = "Human Review";
  assignee_group = "support_triage";
  routing_reason = "Low confidence classification requires human review";
} else if (c.category === "billing") {
  queue = "Billing Support";
  assignee_group = ["high", "urgent"].includes(c.priority)
    ? "billing_l2"
    : "billing_l1";
  routing_reason = "Billing-related ticket";
} else if (c.category === "technical_issue") {
  queue = "Technical Support";
  assignee_group = c.priority === "urgent"
    ? "tech_l2"
    : "tech_l1";
  routing_reason = "Technical issue detected";
} else if (c.category === "account_access") {
  queue = "Account Access";
  assignee_group = "identity_support";
  routing_reason = "Account access or login issue";
} else if (c.category === "feature_request") {
  queue = "Product Feedback";
  assignee_group = "product_ops";
  routing_reason = "Feature request should go to product feedback";
} else if (c.category === "complaint") {
  queue = "Escalations";
  assignee_group = "support_l2";
  routing_reason = "Complaint requires escalation";
} else if (c.category === "how_to_question") {
  queue = "General Support";
  assignee_group = "support_l1";
  routing_reason = "How-to question for first-line support";
} else {
  queue = "Human Review";
  assignee_group = "support_triage";
  routing_reason = "Unknown category";
}

return [
  {
    json: {
      ...item,
      routing: {
        queue,
        assignee_group,
        routing_reason,
        routed_at: new Date().toISOString()
      }
    }
  }
];
